@_cdecl("_nitro_type_coverage_register_intStream_stream")
public func _nitro_type_coverage_register_intStream_stream(
    _ dartPort: Int64,
    _ emitCb: @convention(c) (Int64, Int64) -> Bool
) {
    NitroTypeCoverageRegistry._intStreamCancellables[dartPort] =
        NitroTypeCoverageRegistry.impl?.intStream.sink { item in
            if !emitCb(dartPort, item) {
                NitroTypeCoverageRegistry._intStreamCancellables.removeValue(forKey: dartPort)?.cancel()
            }
        }
}

@_cdecl("_nitro_type_coverage_release_intStream_stream")
public func _nitro_type_coverage_release_intStream_stream(_ dartPort: Int64) {
    NitroTypeCoverageRegistry._intStreamCancellables[dartPort]?.cancel()
    NitroTypeCoverageRegistry._intStreamCancellables.removeValue(forKey: dartPort)
}
@_cdecl("_nitro_type_coverage_register_pointStream_stream")
public func _nitro_type_coverage_register_pointStream_stream(
    _ dartPort: Int64,
    _ emitCb: @convention(c) (Int64, UnsafeMutableRawPointer?) -> Bool
) {
    NitroTypeCoverageRegistry._pointStreamCancellables[dartPort] =
        NitroTypeCoverageRegistry.impl?.pointStream.sink { item in
            let ptr = UnsafeMutablePointer<_TcPointC>.allocate(capacity: 1)
            ptr.initialize(to: _TcPointC.fromSwift(item))
            if !emitCb(dartPort, UnsafeMutableRawPointer(ptr)) {
                ptr.deinitialize(count: 1)
                ptr.deallocate()
                NitroTypeCoverageRegistry._pointStreamCancellables.removeValue(forKey: dartPort)?.cancel()
            }
        }
}

